'-- ============================================================',
'',
'FUNCTION render (',
'    p_dynamic_action IN apex_plugin.t_dynamic_action,',
'    p_plugin         IN apex_plugin.t_plugin',
') RETURN apex_plugin.t_dynamic_action_render_result',
'AS',
'    l_result                       apex_plugin.t_dynamic_action_render_result;',
'    l_region_id   VARCHAR2(100) := p_dynamic_action.attribute_01;',
'    l_col_1       VARCHAR2(100) := p_dynamic_action.attribute_02;',
'    l_col_2       VARCHAR2(100) := p_dynamic_action.attribute_03;',
'    l_col_3       VARCHAR2(100) := p_dynamic_action.attribute_04;',
'    l_col_4       VARCHAR2(100) := p_dynamic_action.attribute_05;',
'    l_col_5       VARCHAR2(100) := p_dynamic_action.attribute_06;',
'    l_error_msg   VARCHAR2(500) := NVL(p_dynamic_action.attribute_07, ''Duplicate Records Found!'');',
'',
'BEGIN',
'    apex_javascript.add_library (',
'        p_name      => ''ig_dup_validator'',',
'        p_directory => p_plugin.file_prefix',
'    );',
'',
'',
'    apex_javascript.add_onload_code (',
'        p_code =>',
'        ''apex.jQuery(document).on("apexreadyend", function() {'' ||',
'            ''igDupValidator.init('' ||',
'            apex_javascript.add_value(l_region_id)                          || ',
'            apex_javascript.add_value(l_col_1)                              || ',
'            apex_javascript.add_value(l_col_2)                              || ',
'            apex_javascript.add_value(l_col_3)                              || ',
'            apex_javascript.add_value(l_col_4)                              || ',
'            apex_javascript.add_value(l_col_5)                              || ',
'            apex_javascript.add_value(l_error_msg)                          || ',
'            apex_javascript.add_value(apex_plugin.get_ajax_identifier,false)      || ',
'                 '');'' ||',
'        ''});''',
'    );',
'',
'    l_result.javascript_function := ''igDupValidator.setup'';',
'    l_result.ajax_identifier     := apex_plugin.get_ajax_identifier;',
'    ',
'    RETURN l_result;',
'',
'END render;',
'',
'',
'FUNCTION ajax (',
'    p_dynamic_action IN apex_plugin.t_dynamic_action,',
'    p_plugin         IN apex_plugin.t_plugin,',
'    p_result         IN OUT NOCOPY apex_plugin.t_dynamic_action_ajax_result',
') RETURN apex_plugin.t_dynamic_action_ajax_result',
'AS',
